import * as React from 'react';
import { graphql } from 'gatsby';
import useIntlHelper from '~src/_i18n/helpers/useIntlHelper';
import Layout from '~src/components/Layout/Layout';
import { PostFeed } from '~src/components/Sections/Posts/PostFeed/PostFeed';

//import * as styles from './careers.module.scss';

const CareersHero = () => {
	const { formatMessage } = useIntlHelper();
	return (
		<header className="site-archive-header outer">
			<div className="inner">
				<div className="inner site-header-content">
					{/* <h2 className="site-description">{formatMessage('navigation.filmography')}</h2> */}
				</div>
				<h1 className="site-title"> Alzahra {formatMessage('navigation.careers')}</h1>
			</div>
		</header>
	);
};

const CareersPage = ({ data }) => {
	return (
		<Layout template="careers" header={<CareersHero />}>
			<div className="inner">
				<h2>We believe in the positive power of stories.</h2>
				<h3>
					To educate. To entertain. To bring people together. <br />
					We make stories more believable, more immersive and more spectacular.
				</h3>
				<p>
					Share what you know
					<br />
					Relish every challenge <br />
					Strive to raise the bar every time <br />
					See the big picture <br />
					Always seek a better way <br />
					Empower and inspire through communication <br />
					Embrace and drive constant change
				</p>

				<div>
					<h2>Open Positions</h2>
					<PostFeed data={data} />
				</div>
			</div>
		</Layout>
	);
};

export default CareersPage;
export const Query = graphql`
	query CareersPageQuery($locale: String!) {
		posts: allMdx(
			sort: { fields: [frontmatter___date], order: DESC }
			filter: { fields: { locale: { eq: $locale }, category: { eq: "posts" } }, frontmatter: { tags: { in: "careers" } } }
		) {
			nodes {
				fields {
					slug
					category
				}
				frontmatter {
					date(formatString: "DD MMMM YYYY")
					title
					featured
					tags
					image {
						childImageSharp {
							gatsbyImageData(layout: FULL_WIDTH, placeholder: TRACED_SVG)
						}
					}
				}
				excerpt(truncate: true, pruneLength: 200)
				timeToRead
			}
		}
	}
`;
